@import url("https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;500;600;700;800;900&family=JetBrains+Mono:wght@400;500;600;700&display=swap");

:root {
  --bg:          #070910;
  --panel:       rgba(13, 18, 30, 0.75);
  --panel-light: rgba(255,255,255,0.03);
  --panel-hover: rgba(255,255,255,0.055);
  --border:      rgba(255,255,255,0.07);
  --border-hi:   rgba(0,242,255,0.25);

  --cyan:        #00f2ff;
  --cyan-dim:    #00c8d4;
  --cyan-glow:   rgba(0,242,255,0.35);
  --purple:      #8b5cf6;
  --purple-glow: rgba(139,92,246,0.3);
  --green:       #10b981;
  --green-glow:  rgba(16,185,129,0.3);
  --red:         #ef4444;
  --red-glow:    rgba(239,68,68,0.3);
  --orange:      #f59e0b;
  --yellow:      #eab308;

  --t1: #f0f4ff;
  --t2: #8b9ab8;
  --t3: #3d4f6e;
  --t4: #1e2a3d;

  --sans: "Outfit", sans-serif;
  --mono: "JetBrains Mono", monospace;
  --glass: blur(24px) saturate(200%);
  --radius: 20px;
  --radius-sm: 12px;

  --sidebar-w: 260px;
  --topbar-h:  64px;
}

/* ─── RESET ─────────────────────────────────────── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

html, body { height: 100%; overflow: hidden; }

body {
  background: var(--bg);
  color: var(--t1);
  font-family: var(--sans);
  background-image:
    radial-gradient(ellipse 60% 40% at 0% 0%,   rgba(0,242,255,0.06) 0%, transparent 70%),
    radial-gradient(ellipse 50% 40% at 100% 100%, rgba(139,92,246,0.07) 0%, transparent 70%),
    radial-gradient(ellipse 40% 30% at 50% 50%, rgba(0,0,0,0.5) 0%, transparent 100%);
}

/* ─── LAYOUT ─────────────────────────────────────── */
#shell {
  display: grid;
  grid-template-columns: var(--sidebar-w) 1fr;
  grid-template-rows: var(--topbar-h) 1fr;
  height: 100vh;
  width: 100vw;
}

/* ─── TOPBAR ─────────────────────────────────────── */
#top {
  grid-column: 1 / -1;
  display: flex;
  align-items: center;
  padding: 0 28px;
  gap: 20px;
  background: rgba(7,9,16,0.85);
  backdrop-filter: var(--glass);
  border-bottom: 1px solid var(--border);
  z-index: 200;
}

.logo {
  display: flex;
  align-items: center;
  gap: 12px;
  cursor: pointer;
  text-decoration: none;
  flex-shrink: 0;
}
.logo-icon {
  width: 36px; height: 36px;
  background: linear-gradient(135deg, var(--cyan), var(--purple));
  border-radius: 10px;
  display: flex; align-items: center; justify-content: center;
  font-size: 18px;
  box-shadow: 0 0 18px var(--cyan-glow);
  flex-shrink: 0;
}
.logo-name {
  font-size: 16px; font-weight: 900;
  letter-spacing: 0.12em;
  background: linear-gradient(90deg, #fff 30%, var(--t2));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
}

/* Status pill */
.top-badge {
  display: flex; align-items: center; gap: 8px;
  padding: 6px 14px;
  background: var(--panel-light);
  border: 1px solid var(--border);
  border-radius: 100px;
  font-size: 11px; font-weight: 700;
  letter-spacing: 0.06em;
  color: var(--cyan);
  flex-shrink: 0;
}
.top-badge .dot {
  width: 7px; height: 7px; border-radius: 50%;
  background: var(--green);
  box-shadow: 0 0 8px var(--green);
  animation: pulse-dot 2s ease-in-out infinite;
}
@keyframes pulse-dot {
  0%,100% { box-shadow: 0 0 6px var(--green); }
  50%      { box-shadow: 0 0 14px var(--green); }
}

/* Top KPIs */
.top-metrics {
  display: flex; align-items: center; gap: 6px;
  margin-left: 12px;
  flex: 1;
}
.top-metric {
  display: flex; align-items: center; gap: 8px;
  padding: 5px 14px;
  background: var(--panel-light);
  border: 1px solid var(--border);
  border-radius: 100px;
  font-size: 11px; color: var(--t2);
  white-space: nowrap;
}
.top-metric b { color: var(--t1); font-weight: 700; font-family: var(--mono); font-size: 12px; }
.top-metric .lbl { font-size: 9px; text-transform: uppercase; letter-spacing: 0.1em; margin-right: 2px; }

#top-cpu-bar, #top-mem-bar {
  width: 40px; height: 3px;
  background: var(--t4);
  border-radius: 2px;
  overflow: hidden;
}
#top-cpu-fill, #top-mem-fill {
  height: 100%; border-radius: 2px;
  background: linear-gradient(90deg, var(--cyan), var(--purple));
  transition: width 1s ease;
  width: 0%;
}

.top-clock {
  margin-left: auto;
  font-family: var(--mono);
  font-size: 14px;
  font-weight: 600;
  color: var(--t2);
  flex-shrink: 0;
}

/* ─── SIDEBAR ─────────────────────────────────────── */
#side {
  background: rgba(7,9,16,0.6);
  backdrop-filter: var(--glass);
  border-right: 1px solid var(--border);
  padding: 24px 0 16px;
  display: flex;
  flex-direction: column;
  gap: 2px;
  overflow: hidden;
}

.nsec {
  padding: 16px 24px 6px;
  font-size: 9px; font-weight: 800;
  color: var(--t3);
  text-transform: uppercase;
  letter-spacing: 0.22em;
}

.ni {
  display: flex; align-items: center;
  gap: 13px;
  padding: 11px 24px;
  color: var(--t2);
  font-size: 13px; font-weight: 500;
  background: transparent;
  border: none; width: 100%;
  cursor: pointer;
  position: relative;
  text-align: left;
  transition: color 0.15s, background 0.15s;
  border-radius: 0;
}
.ni:hover { color: #fff; background: var(--panel-light); }
.ni.on { color: var(--cyan); background: rgba(0,242,255,0.04); }
.ni.on::after {
  content: "";
  position: absolute; right: 0; top: 25%; height: 50%; width: 2px;
  background: var(--cyan);
  box-shadow: 0 0 8px var(--cyan);
  border-radius: 4px 0 0 4px;
}
.ni .ic {
  width: 32px; height: 32px;
  display: flex; align-items: center; justify-content: center;
  border-radius: 8px;
  background: var(--panel-light);
  border: 1px solid var(--border);
  font-size: 15px;
  flex-shrink: 0;
  transition: background 0.15s, border-color 0.15s;
}
.ni.on .ic { background: rgba(0,242,255,0.1); border-color: rgba(0,242,255,0.3); }
.ni .nb {
  margin-left: auto;
  background: var(--cyan); color: #000;
  font-size: 9px; font-weight: 900;
  padding: 2px 7px; border-radius: 5px;
  font-family: var(--mono);
}

.side-spacer { flex: 1; }

/* ─── MAIN CONTENT ─────────────────────────────────── */
#main {
  padding: 24px;
  overflow-y: auto;
  display: flex;
  flex-direction: column;
}

/* ─── VIEWS ─────────────────────────────────────────── */
.view { display: none; flex-direction: column; gap: 20px; animation: vFadeIn 0.3s ease; flex: 1; }
.view.on { display: flex; }

@keyframes vFadeIn {
  from { opacity: 0; transform: translateY(8px); }
  to   { opacity: 1; transform: translateY(0); }
}

/* ─── PANELS ─────────────────────────────────────────── */
.panel {
  background: var(--panel);
  backdrop-filter: var(--glass);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  overflow: hidden;
  box-shadow: 0 4px 24px rgba(0,0,0,0.5);
  transition: border-color 0.2s;
}
.panel:hover { border-color: rgba(255,255,255,0.1); }

.ph {
  padding: 16px 22px;
  border-bottom: 1px solid var(--border);
  display: flex; align-items: center; gap: 10px;
  background: rgba(255,255,255,0.018);
  flex-shrink: 0;
}
.ph .pt { font-size: 11px; font-weight: 800; color: var(--t1); letter-spacing: 0.08em; text-transform: uppercase; }
.ph .pst { margin-left: auto; font-size: 10px; color: var(--t3); font-family: var(--mono); }
.pb { padding: 20px 22px; }

/* ─── KPI ROW ─────────────────────────────────────────── */
.krow {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 16px;
  flex-shrink: 0;
}

.kcard {
  background: var(--panel);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 22px;
  position: relative;
  overflow: hidden;
  transition: transform 0.2s, border-color 0.2s;
  backdrop-filter: var(--glass);
}
.kcard::before {
  content: "";
  position: absolute; top: 0; left: 0; right: 0; height: 1px;
  background: linear-gradient(90deg, transparent, rgba(255,255,255,0.06), transparent);
}
.kcard:hover { transform: translateY(-2px); border-color: rgba(0,242,255,0.15); }

.klbl {
  font-size: 10px; font-weight: 700;
  color: var(--t3); text-transform: uppercase;
  letter-spacing: 0.12em; margin-bottom: 10px;
}
.kval {
  font-size: 28px; font-weight: 800;
  font-family: var(--mono);
  color: #fff;
  line-height: 1;
}
.ksub { font-size: 11px; color: var(--t2); margin-top: 8px; }

.kcard .kicon {
  position: absolute; right: 18px; top: 18px;
  font-size: 22px; opacity: 0.15;
}

/* progress bar in kcard */
.kbar { margin-top: 10px; height: 3px; background: var(--t4); border-radius: 2px; overflow: hidden; }
.kbar-fill { height: 100%; border-radius: 2px; background: linear-gradient(90deg, var(--cyan), var(--purple)); transition: width 1s ease; }

/* ─── TABLES ─────────────────────────────────────────── */
.stbl { width: 100%; border-collapse: collapse; }
.stbl th {
  text-align: left; padding: 12px 16px;
  font-size: 9px; font-weight: 800; color: var(--t3);
  text-transform: uppercase; letter-spacing: 0.12em;
  border-bottom: 1px solid var(--border);
}
.stbl td {
  padding: 13px 16px; font-size: 13px;
  border-bottom: 1px solid var(--border);
  color: var(--t2);
  transition: color 0.15s, background 0.15s;
}
.stbl tr:last-child td { border-bottom: none; }
.stbl tbody tr:hover td { color: #fff; background: var(--panel-hover); }

/* ─── PILLS / BADGES ─────────────────────────────────── */
.pill {
  display: inline-flex; align-items: center;
  padding: 3px 9px; border-radius: 5px;
  font-size: 10px; font-weight: 800;
  text-transform: uppercase; letter-spacing: 0.06em;
  white-space: nowrap;
}
.pill-up   { background: rgba(16,185,129,0.12); color: var(--green); }
.pill-down { background: rgba(239,68,68,0.12);  color: var(--red); }
.pill-warn { background: rgba(245,158,11,0.12); color: var(--orange); }
.pill-cyan { background: rgba(0,242,255,0.1);   color: var(--cyan); }
.pill-dim  { background: var(--panel-light);    color: var(--t3); border: 1px solid var(--border); }

/* legacy aliases */
.pill.u { background: rgba(16,185,129,0.12); color: var(--green); }
.pill.d { background: rgba(239,68,68,0.12);  color: var(--red); }

/* ─── STATUS DOTS ─────────────────────────────────────── */
.sdot {
  display: inline-block; width: 8px; height: 8px; border-radius: 50%;
  flex-shrink: 0;
}
.sdot.up   { background: var(--green); box-shadow: 0 0 6px var(--green); }
.sdot.down { background: var(--red);   box-shadow: 0 0 6px var(--red); }
.sdot.warn { background: var(--orange); box-shadow: 0 0 6px var(--orange); }

/* ─── BUTTONS ─────────────────────────────────────────── */
.btn {
  display: inline-flex; align-items: center; justify-content: center; gap: 6px;
  padding: 10px 20px; border-radius: var(--radius-sm);
  font-size: 11px; font-weight: 800; font-family: var(--sans);
  letter-spacing: 0.06em; text-transform: uppercase;
  border: none; cursor: pointer;
  transition: all 0.18s;
}
.btn-primary {
  background: var(--cyan); color: #000;
}
.btn-primary:hover { transform: scale(1.03); box-shadow: 0 0 22px var(--cyan-glow); }

.btn-danger {
  background: rgba(239,68,68,0.1);
  color: var(--red); border: 1px solid rgba(239,68,68,0.3);
}
.btn-danger:hover { background: var(--red); color: #fff; box-shadow: 0 0 16px var(--red-glow); }

.btn-ghost {
  background: var(--panel-light);
  color: var(--t2); border: 1px solid var(--border);
}
.btn-ghost:hover { color: #fff; border-color: rgba(255,255,255,0.15); }

/* ─── AGENT CARDS ─────────────────────────────────────── */
.agent-card {
  background: var(--panel-light);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 16px;
  transition: transform 0.2s, border-color 0.2s;
  display: flex; flex-direction: column; gap: 10px;
}
.agent-card:hover { transform: translateY(-2px); border-color: rgba(0,242,255,0.2); }
.agent-card.online { border-color: rgba(16,185,129,0.2); }
.agent-card.online:hover { border-color: rgba(16,185,129,0.4); }

.agent-name { font-size: 12px; font-weight: 800; color: #fff; letter-spacing: 0.04em; }
.agent-desc { font-size: 11px; color: var(--t2); line-height: 1.45; }
.agent-caps { display: flex; gap: 4px; flex-wrap: wrap; }
.agent-cap {
  font-size: 9px; color: var(--cyan); font-family: var(--mono);
  border: 1px solid rgba(0,242,255,0.18); padding: 2px 6px; border-radius: 4px;
}

/* ─── MAESTRO ─────────────────────────────────────────── */
.ma-brain {
  font-size: 56px;
  filter: drop-shadow(0 0 24px rgba(139,92,246,0.5));
  animation: float 4s ease-in-out infinite;
}
@keyframes float {
  0%,100% { transform: translateY(0); }
  50%      { transform: translateY(-8px); }
}

.ma-input-wrap {
  width: 100%; max-width: 560px;
  position: relative;
}
.ma-input {
  width: 100%;
  background: var(--panel-light);
  border: 1px solid var(--border);
  padding: 16px 120px 16px 20px;
  border-radius: var(--radius);
  color: #fff; font-family: var(--sans); font-size: 14px;
  outline: none;
  transition: border-color 0.2s;
}
.ma-input:focus { border-color: var(--cyan); box-shadow: 0 0 0 3px rgba(0,242,255,0.08); }
.ma-input::placeholder { color: var(--t3); }
.ma-deploy-btn {
  position: absolute; right: 8px; top: 8px;
}

/* Maestro log */
.ma-log {
  width: 100%; max-width: 560px;
  background: rgba(0,0,0,0.3);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 14px;
  font-family: var(--mono); font-size: 11px;
  color: var(--cyan); line-height: 1.8;
  max-height: 160px; overflow-y: auto;
  text-align: left;
}

/* ─── CHART ─────────────────────────────────────────────── */
.chart-wrap {
  background: rgba(0,0,0,0.25);
  border-radius: var(--radius-sm);
  overflow: hidden;
  flex: 1;
  min-height: 0;
}

/* ─── N8N / AUTOMATIONS ─────────────────────────────────── */
.workflow-card {
  background: var(--panel-light);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 16px 18px;
  display: flex; align-items: center; gap: 16px;
  transition: border-color 0.2s, background 0.2s;
  cursor: pointer;
}
.workflow-card:hover { background: var(--panel-hover); border-color: rgba(0,242,255,0.2); }
.wf-icon {
  width: 42px; height: 42px;
  background: rgba(0,242,255,0.08);
  border: 1px solid rgba(0,242,255,0.2);
  border-radius: 10px;
  display: flex; align-items: center; justify-content: center;
  font-size: 20px; flex-shrink: 0;
}
.wf-name { font-size: 13px; font-weight: 700; color: #fff; }
.wf-desc { font-size: 11px; color: var(--t2); margin-top: 2px; }

/* ─── KNOWLEDGE ─────────────────────────────────────────── */
.notion-card {
  background: var(--panel-light);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 14px 16px;
  display: flex; align-items: flex-start; gap: 14px;
  transition: border-color 0.2s, background 0.2s;
  cursor: pointer;
}
.notion-card:hover { background: var(--panel-hover); border-color: rgba(139,92,246,0.3); }
.notion-icon { font-size: 22px; flex-shrink: 0; margin-top: 1px; }
.notion-title { font-size: 13px; font-weight: 600; color: #fff; }
.notion-meta  { font-size: 10px; color: var(--t3); margin-top: 3px; font-family: var(--mono); }

/* ─── EMPTY STATE ─────────────────────────────────────────── */
.empty-state {
  display: flex; flex-direction: column; align-items: center; justify-content: center;
  padding: 48px 24px; gap: 12px; color: var(--t3);
}
.empty-state .es-icon { font-size: 36px; opacity: 0.4; }
.empty-state .es-msg { font-size: 12px; }

/* ─── AI BUBBLE ─────────────────────────────────────────── */
.ai-bubble {
  background: rgba(0,242,255,0.04);
  border-left: 2px solid var(--cyan);
  padding: 12px 14px;
  border-radius: 0 8px 8px 0;
  font-family: var(--mono);
  font-size: 11px; color: var(--cyan); line-height: 1.7;
}

/* ─── GRID HELPERS ─────────────────────────────────────── */
.grid-2 { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; }
.grid-3 { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 16px; }
.col    { display: flex; flex-direction: column; gap: 16px; }
.row    { display: flex; gap: 16px; align-items: stretch; }
.flex1  { flex: 1; min-width: 0; }

/* ─── TRADING LAYOUT ─────────────────────────────────────── */
.trading-layout {
  display: grid;
  grid-template-columns: 300px 1fr 300px;
  gap: 16px;
  flex: 1;
  min-height: 0;
}

/* ─── SCROLLBAR ─────────────────────────────────────────── */
::-webkit-scrollbar { width: 5px; height: 5px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: var(--t4); border-radius: 8px; }
::-webkit-scrollbar-thumb:hover { background: var(--t3); }

/* ─── LOADING SPINNER ─────────────────────────────────────── */
.spinner {
  display: inline-block; width: 14px; height: 14px;
  border: 2px solid var(--t4);
  border-top-color: var(--cyan);
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}
@keyframes spin { to { transform: rotate(360deg); } }

/* ─── SETTINGS FORM ─────────────────────────────────────── */
.form-group { margin-bottom: 18px; }
.form-label { font-size: 10px; font-weight: 700; color: var(--t3); text-transform: uppercase; letter-spacing: 0.1em; display: block; margin-bottom: 6px; }
.form-val {
  background: var(--panel-light);
  border: 1px solid var(--border);
  padding: 10px 14px;
  border-radius: var(--radius-sm);
  font-family: var(--mono); font-size: 12px; color: var(--t1);
}

